questionvariables.text:
/* Q6: WPT Efficiency and Minimum Frequency Design */
idx: 1 + rand(5);

/* Parameter sets */
L1_uH_list: [5, 8, 10, 15, 20];
L2_uH_list: [3, 5, 8, 10, 12];
R1_list: [0.3, 0.5, 0.5, 0.8, 1.0];
R2_list: [0.5, 0.8, 0.8, 1.0, 1.5];
k_list: [0.2, 0.3, 0.4, 0.5, 0.3];
f_kHz_list: [85, 100, 150, 200, 85];

L1_uH: L1_uH_list[idx];
L2_uH: L2_uH_list[idx];
R1: R1_list[idx];
R2: R2_list[idx];
k_val: k_list[idx];
f_kHz: f_kHz_list[idx];

/* Convert to SI */
L1: L1_uH * 10^(-6);
L2: L2_uH * 10^(-6);
f_Hz: f_kHz * 10^3;
omega_val: 2*%pi*f_Hz;

/* (a) Mutual inductance */
M_val: float(k_val * sqrt(L1 * L2));
tans1: M_val;
M_uH_disp: float(M_val * 10^6);

/* (b) Coupling reactance omega*M */
wM_val: float(omega_val * M_val);
tans2: wM_val;

/* (c) Power transfer efficiency */
eta_val: float(wM_val^2 / (R1*R2 + wM_val^2));
tans3: eta_val;

/* (d) Minimum frequency for 95% efficiency */
/* eta >= 0.95 => (wM)^2 >= 19*R1*R2 => w >= sqrt(19*R1*R2)/M */
/* f_min = sqrt(19*R1*R2) / (2*pi*M) */
omega_min: float(sqrt(19*R1*R2) / M_val);
f_min_Hz: float(omega_min / (2*%pi));
f_min_kHz: float(f_min_Hz / 1000);
tans4: f_min_kHz;

/* (e) Module classification MCQ */
/* Correct: M1 + M2 + M3 (no M4 — wavelength >> coil size at ~100 kHz) */
ta5: random_permutation([
  [1, true, "M1 + M2 + M3 (Circuits + Laplace + Magnetics)"],
  [2, false, "All four modules (M1 + M2 + M3 + M4)"],
  [3, false, "Only M3 (Magnetics)"],
  [4, false, "M3 + M4 (Magnetics + Waves)"]
]);

/* Error model values */
/* E1: M = k*(L1+L2) instead of k*sqrt(L1*L2) */
M_err_sum: float(k_val * (L1 + L2));
/* E2: forgot omega, used just f*M instead of 2*pi*f*M */
wM_err_noomega: float(f_Hz * M_val);
/* E3: efficiency > 1 (impossible) */

feedbackvariables.text:
/* Check if student forgot 2*pi (used omega directly as f) */
f_min_err_nopi: float(sqrt(19*R1*R2) / (M_val) / 1000);
err_nopi_flag: if abs(ans4 - f_min_err_nopi)/abs(f_min_err_nopi) < 0.06 then 1 else 0;
